function parseRange(s) {
    const hyphenIndex = s.indexOf('-');
    if (hyphenIndex === -1) {
        return [Number(s)];
    }
    if (hyphenIndex === 0) {
        return [Number(s)];
    }
    const a = Number(s.slice(0, hyphenIndex));
    const b = Number(s.slice(hyphenIndex + 1));
    const result = [];
    if (a <= b) {
        for (let i = a; i <= b; i++) result.push(i);
    } else {
        for (let i = a; i >= b; i--) result.push(i);
    }
    return result;
}
